INSERT INTO words (word, category_id, position, tag, zh, en, example_en, example_zh, synonyms) VALUES
  ('send', 'op', 16, 'OP', '发送；派遣；寄出', 'cause a person, message, or thing to go somewhere', 'Send the letter before the end of the day.', '今天结束前把信寄出去。', '[{"w":"see","def":"see: 相关的动作或关系词","vs":"与 send 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"see\" / \"send\" 的替换练习"},{"w":"may","def":"may: 可帮助扩展句型的基础词","vs":"与 send 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"may\" / \"send\" 的替换练习"},{"w":"will","def":"will: 同一组 Basic English 操作词","vs":"与 send 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"will\" / \"send\" 的替换练习"}]'),
  ('may', 'op', 17, 'OP', '可以；可能；表示许可或可能性', 'show permission or possibility', 'You may use my pen if you give it back.', '如果你会还给我，你可以用我的笔。', '[{"w":"send","def":"send: 相关的动作或关系词","vs":"与 may 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"send\" / \"may\" 的替换练习"},{"w":"will","def":"will: 可帮助扩展句型的基础词","vs":"与 may 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"will\" / \"may\" 的替换练习"},{"w":"about","def":"about: 同一组 Basic English 操作词","vs":"与 may 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"about\" / \"may\" 的替换练习"}]'),
  ('will', 'op', 18, 'OP', '将要；愿意；表示未来或意愿', 'show future action or a person''s intention', 'I will send the answer tomorrow morning.', '我明天早上会把答案发出去。', '[{"w":"may","def":"may: 相关的动作或关系词","vs":"与 will 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"may\" / \"will\" 的替换练习"},{"w":"about","def":"about: 可帮助扩展句型的基础词","vs":"与 will 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"about\" / \"will\" 的替换练习"},{"w":"across","def":"across: 同一组 Basic English 操作词","vs":"与 will 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"across\" / \"will\" 的替换练习"}]'),
  ('about', 'op', 19, 'OP', '关于；大约；在周围', 'on the subject of, near in number, or around', 'This short story is about a boy and his dog.', '这个短故事是关于一个男孩和他的狗。', '[{"w":"will","def":"will: 相关的动作或关系词","vs":"与 about 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"will\" / \"about\" 的替换练习"},{"w":"across","def":"across: 可帮助扩展句型的基础词","vs":"与 about 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"across\" / \"about\" 的替换练习"},{"w":"after","def":"after: 同一组 Basic English 操作词","vs":"与 about 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"after\" / \"about\" 的替换练习"}]'),
  ('across', 'op', 20, 'OP', '横过；在对面', 'from one side to the other side', 'The bridge goes across the river.', '这座桥横跨河流。', '[{"w":"about","def":"about: 相关的动作或关系词","vs":"与 across 相比，用于和主词比较动作方向、许可或连接关系","use":"造句、改写、基础语法替换，例如 \"about\" / \"across\" 的替换练习"},{"w":"after","def":"after: 可帮助扩展句型的基础词","vs":"与 across 相比，比主词更偏向另一个动作阶段或语气","use":"短句练习、问答转换，例如 \"after\" / \"across\" 的替换练习"},{"w":"against","def":"against: 同一组 Basic English 操作词","vs":"与 across 相比，保留基础含义，但句中功能不同","use":"动词、介词、连词的搭配训练，例如 \"against\" / \"across\" 的替换练习"}]');
